const saveData = (d) => { try{localStorage.setItem(STORAGE_KEY,JSON.stringify(d));}catch{} };

async function callClaude(system, userMsg, docContent=null) {
  const apiKey = import.meta.env.VITE_ANTHROPIC_API_KEY;
  const content = docContent ? [docContent, {type:"text",text:userMsg}] : userMsg;
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method:"POST",
    headers:{"Content-Type":"application/json","x-api-key":apiKey,"anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},
    body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:2000,system,messages:[{role:"user",content}]})
  });
  if(!res.ok) throw new Error(`API ${res.status}`);
  const data = await res.json();
  return data.content.map(i=>i.text||"").join("");
}

// ─── UI PRIMITIVES ───
function TagInput({value=[],onChange,placeholder}) {
  const [inp,setInp]=useState("");
  const add=e=>{if((e.key==="Enter"||e.key===",")&&inp.trim()){e.preventDefault();if(!value.includes(inp.trim()))onChange([...value,inp.trim()]);setInp("");}};
  return <div style={{display:"flex",flexWrap:"wrap",gap:5,padding:"8px 10px",background:"#f9fafb",border:"1px solid #e5e7eb",borderRadius:8,minHeight:40}}>
    {value.map((t,i)=><span key={i} style={{background:"#fff",border:"1px solid #e5e7eb",color:"#374151",padding:"2px 10px",borderRadius:20,fontSize:12,display:"flex",alignItems:"center",gap:5}}>
      {t}<span onClick={()=>onChange(value.filter((_,j)=>j!==i))} style={{cursor:"pointer",color:"#9ca3af",fontWeight:700}}>×</span>
    </span>)}
    <input value={inp} onChange={e=>setInp(e.target.value)} onKeyDown={add} placeholder={placeholder}
      style={{background:"transparent",border:"none",outline:"none",color:"#374151",fontSize:13,minWidth:100,flex:1}}/>
  </div>;
}

function Avatar({persona,size=40}) {
  const url=persona.photo||PHOTO_URLS[persona.id];
  const [err,setErr]=useState(false);
  if(url&&!err) return <img src={url} onError={()=>setErr(true)} alt={persona.name}
    style={{width:size,height:size,borderRadius:"50%",objectFit:"cover",objectPosition:"top",flexShrink:0}}/>;
  return <div style={{width:size,height:size,borderRadius:"50%",background:"#f3f4f6",display:"flex",alignItems:"center",justifyContent:"center",fontSize:size*0.44,flexShrink:0}}>{persona.emoji||"👤"}</div>;
}

function TypeBadge({type,color,small=false}) {
  return <span style={{background:color+"15",color,fontSize:small?10:11,padding:small?"2px 7px":"3px 10px",borderRadius:20,fontWeight:600}}>{type}</span>;
}

function ScoreRing({score,color,size=80}) {
  const r=size*0.38,c=2*Math.PI*r,dash=(score/100)*c;
  return <div style={{position:"relative",width:size,height:size,flexShrink:0}}>
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} style={{transform:"rotate(-90deg)"}}>
      <circle cx={size/2} cy={size/2} r={r} fill="none" stroke="#f3f4f6" strokeWidth={size*0.08}/>
      <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={color} strokeWidth={size*0.08} strokeDasharray={`${dash} ${c}`} strokeLinecap="round"/>
    </svg>
    <div style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",textAlign:"center",lineHeight:1}}>
      <div style={{fontSize:size*0.28,fontWeight:700,color}}>{score}</div>
      <div style={{fontSize:size*0.13,color:"#9ca3af"}}>/100</div>
    </div>
  </div>;
}

function DimBar({label,value}) {
  const c=value>=70?"#16a34a":value>=40?"#d97706":"#dc2626";
  return <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
    <div style={{fontSize:12,color:"#6b7280",width:90,flexShrink:0}}>{label}</div>
    <div style={{flex:1,height:4,background:"#f3f4f6",borderRadius:4,overflow:"hidden"}}>
      <div style={{width:`${value}%`,height:"100%",background:c,borderRadius:4,transition:"width 0.8s ease"}}/>
    </div>
    <div style={{fontSize:11,fontWeight:700,color:c,width:24,textAlign:"right"}}>{value}</div>
  </div>;
}

// ─── SPACES HOME ───
function SpacesHome({spaces,personas,onOpenSpace,onCreateSpace,onDeleteSpace}) {
  return <div style={{minHeight:"100vh",background:"#f8fafc"}}>
    {/* Hero */}
    <div style={{background:"#fff",borderBottom:"1px solid #f1f5f9",padding:"48px 56px 40px"}}>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:24}}>
        <div style={{width:34,height:34,background:"#0f172a",borderRadius:9,display:"flex",alignItems:"center",justifyContent:"center"}}>
          <span style={{color:"#fff",fontSize:17,fontWeight:800}}>P</span>
        </div>
        <span style={{fontSize:16,fontWeight:700,color:"#0f172a",letterSpacing:-0.3}}>PersonaLab</span>
      </div>
      <h1 style={{fontSize:38,fontWeight:700,color:"#0f172a",margin:"0 0 10px",letterSpacing:-1,lineHeight:1.15}}>
        Vos espaces de travail
      </h1>
      <p style={{fontSize:16,color:"#64748b",margin:0,maxWidth:480,lineHeight:1.6}}>
        Chaque espace regroupe un ensemble de personas autour d'un projet éditorial. Testez vos contenus, actualisez vos profils, construisez votre connaissance des audiences.
      </p>
    </div>

    {/* Spaces grid */}
    <div style={{padding:"40px 56px"}}>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(300px,1fr))",gap:20}}>

        {/* Existing spaces */}
        {spaces.map(space => {
          const spacePersonas = personas.filter(p => space.personaIds?.includes(p.id));
          return <div key={space.id} onClick={()=>onOpenSpace(space.id)}
            style={{background:"#fff",border:"1px solid #f1f5f9",borderRadius:16,padding:"24px",cursor:"pointer",transition:"all 0.2s",position:"relative"}}
            onMouseEnter={e=>{e.currentTarget.style.boxShadow="0 4px 20px rgba(0,0,0,0.08)";e.currentTarget.style.borderColor="#e2e8f0";e.currentTarget.style.transform="translateY(-2px)";}}
            onMouseLeave={e=>{e.currentTarget.style.boxShadow="none";e.currentTarget.style.borderColor="#f1f5f9";e.currentTarget.style.transform="translateY(0)";}}>

            {/* Delete button */}
            <button onClick={e=>{e.stopPropagation();onDeleteSpace(space.id);}}
              style={{position:"absolute",top:14,right:14,background:"transparent",border:"none",color:"#cbd5e1",cursor:"pointer",fontSize:16,padding:"2px 6px",borderRadius:6}}
              onMouseEnter={e=>e.currentTarget.style.color="#ef4444"}
              onMouseLeave={e=>e.currentTarget.style.color="#cbd5e1"}>×</button>

            {/* Space header */}
            <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:16}}>
              <div style={{width:44,height:44,borderRadius:12,background:space.color+"15",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22}}>
                {space.icon}
              </div>
              <div>
                <div style={{fontWeight:700,fontSize:15,color:"#0f172a",lineHeight:1.2}}>{space.name}</div>
                <div style={{fontSize:12,color:"#94a3b8",marginTop:2}}>{spacePersonas.length} persona{spacePersonas.length>1?"s":""}</div>
              </div>
            </div>

            {/* Description */}
            {space.description&&<p style={{fontSize:12,color:"#64748b",margin:"0 0 16px",lineHeight:1.5}}>{space.description}</p>}

            {/* Persona avatars */}
            <div style={{display:"flex",alignItems:"center",gap:-6}}>
              {spacePersonas.slice(0,6).map((p,i)=>(
                <div key={p.id} style={{marginLeft:i>0?-8:0,border:"2px solid #fff",borderRadius:"50%",zIndex:6-i}}>
                  <Avatar persona={p} size={30}/>
                </div>
              ))}
              {spacePersonas.length>6&&<div style={{marginLeft:4,fontSize:12,color:"#94a3b8",fontWeight:500}}>+{spacePersonas.length-6}</div>}
            </div>

            {/* Bottom bar */}
            <div style={{marginTop:16,paddingTop:14,borderTop:"1px solid #f8fafc",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <div style={{width:8,height:8,borderRadius:"50%",background:space.color}}/>
              <span style={{fontSize:11,color:"#94a3b8"}}>Ouvrir l'espace →</span>
            </div>
          </div>;
        })}

        {/* Create new space */}
        <div onClick={onCreateSpace}
          style={{background:"#fff",border:"2px dashed #e2e8f0",borderRadius:16,padding:"24px",cursor:"pointer",transition:"all 0.2s",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",minHeight:200,gap:12}}
          onMouseEnter={e=>{e.currentTarget.style.borderColor="#94a3b8";e.currentTarget.style.background="#f8fafc";}}
          onMouseLeave={e=>{e.currentTarget.style.borderColor="#e2e8f0";e.currentTarget.style.background="#fff";}}>
          <div style={{width:48,height:48,borderRadius:12,background:"#f8fafc",border:"1px solid #e2e8f0",display:"flex",alignItems:"center",justifyContent:"center",fontSize:24}}>+</div>
          <div style={{textAlign:"center"}}>
            <div style={{fontWeight:600,fontSize:14,color:"#374151"}}>Nouvel espace</div>
            <div style={{fontSize:12,color:"#94a3b8",marginTop:4}}>Créer un nouveau projet</div>
          </div>
        </div>

      </div>
    </div>
  </div>;
}

// ─── CREATE SPACE MODAL ───
function CreateSpaceModal({onSave,onCancel}) {
  const [name,setName]=useState("");
  const [desc,setDesc]=useState("");
  const [color,setColor]=useState(SPACE_COLORS[0]);
  const [icon,setIcon]=useState(SPACE_ICONS[0]);
  const fs={width:"100%",background:"#f9fafb",border:"1px solid #e5e7eb",borderRadius:8,color:"#111827",padding:"9px 12px",fontSize:14,outline:"none",boxSizing:"border-box"};
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.4)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000}}>
    <div style={{background:"#fff",borderRadius:16,padding:"32px",width:480,boxShadow:"0 20px 60px rgba(0,0,0,0.15)"}}>
      <h3 style={{fontSize:20,fontWeight:700,color:"#0f172a",margin:"0 0 24px"}}>Nouvel espace</h3>

      <div style={{marginBottom:16}}>
        <label style={{fontSize:11,fontWeight:600,color:"#6b7280",textTransform:"uppercase",letterSpacing:1,display:"block",marginBottom:6}}>Nom de l'espace</label>
        <input value={name} onChange={e=>setName(e.target.value)} style={fs} placeholder="Ex: Repositionnement France TV"/>
      </div>

      <div style={{marginBottom:16}}>
        <label style={{fontSize:11,fontWeight:600,color:"#6b7280",textTransform:"uppercase",letterSpacing:1,display:"block",marginBottom:6}}>Description (optionnel)</label>
        <input value={desc} onChange={e=>setDesc(e.target.value)} style={fs} placeholder="Ex: Étude audience 25-49 ans"/>
      </div>

      <div style={{marginBottom:16}}>
        <label style={{fontSize:11,fontWeight:600,color:"#6b7280",textTransform:"uppercase",letterSpacing:1,display:"block",marginBottom:8}}>Icône</label>
        <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
          {SPACE_ICONS.map(i=><button key={i} onClick={()=>setIcon(i)}
            style={{width:40,height:40,borderRadius:8,border:`2px solid ${icon===i?"#0f172a":"#e2e8f0"}`,background:icon===i?"#f8fafc":"#fff",fontSize:20,cursor:"pointer"}}>
            {i}</button>)}
        </div>
      </div>

      <div style={{marginBottom:24}}>
        <label style={{fontSize:11,fontWeight:600,color:"#6b7280",textTransform:"uppercase",letterSpacing:1,display:"block",marginBottom:8}}>Couleur</label>
        <div style={{display:"flex",gap:8}}>
          {SPACE_COLORS.map(c=><button key={c} onClick={()=>setColor(c)}
            style={{width:28,height:28,borderRadius:"50%",background:c,border:`3px solid ${color===c?"#0f172a":"transparent"}`,cursor:"pointer",outline:`2px solid ${color===c?c:"transparent"}`,outlineOffset:2}}/>)}
        </div>
      </div>

      <div style={{display:"flex",gap:10}}>
        <button onClick={()=>name.trim()&&onSave({id:Date.now().toString(),name,description:desc,color,icon,personaIds:[],createdAt:new Date().toISOString().split("T")[0]})}
          disabled={!name.trim()}
          style={{flex:1,background:name.trim()?"#0f172a":"#f1f5f9",border:"none",color:name.trim()?"#fff":"#9ca3af",padding:"11px",borderRadius:10,cursor:name.trim()?"pointer":"not-allowed",fontWeight:600,fontSize:14}}>
          Créer l'espace
        </button>
        <button onClick={onCancel} style={{background:"#f8fafc",border:"1px solid #e2e8f0",color:"#374151",padding:"11px 20px",borderRadius:10,cursor:"pointer"}}>Annuler</button>
      </div>
    </div>
  </div>;
}

