// ─── TEST PANEL ───
function TestPanel({persona,allPersonas,onSelectPersona}) {
  const [content,setContent]=useState("");
  const [loading,setLoading]=useState(false);
  const [result,setResult]=useState(null);
  const [error,setError]=useState(null);
  const [fileLoading,setFileLoading]=useState(false);

  // When persona changes (cross-test navigation), restore saved content
  useEffect(()=>{
    const saved=sessionStorage.getItem("crossTestContent");
    if(saved){
      sessionStorage.removeItem("crossTestContent");
      setContent(saved);
      setResult(null);
    }
  },[persona.id]);
  const scoreColor=result?(result.score>=70?"#16a34a":result.score>=40?"#d97706":"#dc2626"):"#0f172a";

  const readFile=async(file)=>{
    setFileLoading(true);
    sessionStorage.removeItem("lastDocB64");
    sessionStorage.removeItem("lastDocType");
    try {
      const name = file.name.toLowerCase();
      const type = file.type;

      const isPDF = type==="application/pdf";
      const isDocx = name.endsWith(".docx") || type==="application/vnd.openxmlformats-officedocument.wordprocessingml.document";
      const isText = type.startsWith("text/") || name.endsWith(".txt") || name.endsWith(".md");
      const isAudio = type.startsWith("audio/") || name.endsWith(".mp3") || name.endsWith(".wav") || name.endsWith(".m4a") || name.endsWith(".ogg") || name.endsWith(".flac") || name.endsWith(".aac") || name.endsWith(".webm");
      const isImage = type.startsWith("image/") || name.endsWith(".jpg") || name.endsWith(".jpeg") || name.endsWith(".png") || name.endsWith(".gif") || name.endsWith(".webp");

      const toBase64 = (f,asDataURL=false) => new Promise((res,rej)=>{
        const r=new FileReader();
        r.onload=()=>res(asDataURL ? r.result : r.result.split(",")[1]);
        r.onerror=rej;
        r.readAsDataURL(f);
      });

      if(isPDF) {
        const base64 = await toBase64(file);
        setContent(`[PDF : ${file.name}]`);
        sessionStorage.setItem("lastDocB64", base64);
        sessionStorage.setItem("lastDocType", "pdf");
        sessionStorage.setItem("lastDocName", file.name);

      } else if(isDocx) {
        const arrBuf = await new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res(r.result);r.onerror=rej;r.readAsArrayBuffer(file);});
        const result = await mammoth.extractRawText({arrayBuffer: arrBuf});
        const extracted = result.value?.trim().substring(0,6000);
        setContent(extracted || "[Document Word vide — collez le contenu manuellement]");

      } else if(isText) {
        const text = await new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res(r.result);r.onerror=rej;r.readAsText(file,"UTF-8");});
        setContent(text.substring(0,6000));

      } else if(isAudio) {
        const base64 = await toBase64(file);
        const audioMime = type || "audio/mpeg";
        setContent(`[Audio : ${file.name}]`);
        sessionStorage.setItem("lastDocB64", base64);
        sessionStorage.setItem("lastDocType", "audio");
        sessionStorage.setItem("lastDocMime", audioMime);
        sessionStorage.setItem("lastDocName", file.name);

      } else if(isImage) {
        const base64 = await toBase64(file);
        const imgMime = type || "image/jpeg";
        setContent(`[Image : ${file.name}]`);
        sessionStorage.setItem("lastDocB64", base64);
        sessionStorage.setItem("lastDocType", "image");
        sessionStorage.setItem("lastDocMime", imgMime);
        sessionStorage.setItem("lastDocName", file.name);

      } else {
        setContent(`[Format non supporté : ${file.name}]

Formats acceptés :
· Documents : PDF, Word (.docx), TXT, Markdown
· Audio : MP3, WAV, M4A, OGG, FLAC, AAC
· Images : JPG, PNG, GIF, WebP

Pour la vidéo, exportez la piste audio ou collez le transcript ci-dessous.`);
      }

    } catch(e) {
      setContent(`[Erreur de lecture : ${e.message}]

Essayez de copier-coller le contenu directement.`);
    }
    setFileLoading(false);
  };
;

  const analyze=async()=>{
    if(!content.trim()) return;
    setLoading(true);setResult(null);setError(null);
    const sys=`Tu es ${persona.name}, ${persona.age}, ${persona.job}, vivant à ${persona.city||"Afrique/Maghreb"}.
Type d'audience : ${persona.type}. Bio : ${persona.bio}
Médias : ${persona.medias?.join(", ")}. Intérêts : ${persona.interests?.join(", ")}.
Frustrations : ${persona.frustrations?.join(", ")}. Accroches : ${persona.hooks?.join(", ")}.
Déclencheurs : ${persona.triggers?.join(", ")}.
Revenus : ${persona.marketData?.revenu||"non précisé"}. Forfait : ${persona.marketData?.forfait||"non précisé"}.

Évalue ce contenu UNIQUEMENT depuis ton point de vue authentique. Sois précis, factuel, ancré dans ton profil réel. Pas de généralités — cite des éléments concrets du contenu.

Réponds UNIQUEMENT en JSON valide sans backticks :
{"score":<0-100>,"verdict":"<titre percutant max 8 mots>","ressenti":{"accroche":"<1-2 phrases : les premières secondes/lignes t'ont-elles capturé ? Cite un élément concret>","identification":"<1-2 phrases : tu te reconnais ? Les personnages, situations, codes culturels sonnent-ils juste ?>","friction":"<1-2 phrases : ce qui accroche, dérange ou sonne faux — direct, ancré dans ton profil>","intention":"<1-2 phrases : tu continuerais ? Tu partagerais avec qui — ou pourquoi tu décrocherais>"},"dimensions":{"Pertinence":<0-100>,"Format":<0-100>,"Ton":<0-100>,"Engagement":<0-100>},"recommandations":["<conseil concret ancré dans ton profil 1>","<conseil 2>","<conseil 3>"]}`;
    try{
      const docB64=sessionStorage.getItem("lastDocB64");
      const docType=sessionStorage.getItem("lastDocType");
      const docMime=sessionStorage.getItem("lastDocMime")||"";
      const docName=sessionStorage.getItem("lastDocName")||"fichier";
      let doc=null;

      if(docB64&&docType==="pdf") {
        doc={type:"document",source:{type:"base64",media_type:"application/pdf",data:docB64}};
      } else if(docB64&&docType==="audio") {
        doc={type:"document",source:{type:"base64",media_type:docMime,data:docB64}};
      } else if(docB64&&docType==="image") {
        doc={type:"image",source:{type:"base64",media_type:docMime,data:docB64}};
      }

      const userMsg = docType==="audio"
        ? `Transcris et analyse ce fichier audio "${docName}" depuis le point de vue de ${persona.name} :

${content}`
        : docType==="image"
        ? `Analyse cette image "${docName}" comme contenu éditorial depuis le point de vue de ${persona.name} :

${content}`
        : `Analyse ce contenu :\n\n${content}`;

      const text=await callClaude(sys, userMsg, doc);
      setResult(JSON.parse(text.replace(/\`\`\`json|\`\`\`/g,"").trim()));
    }catch(e){setError("Erreur d'analyse. Vérifiez la connexion.");}
    finally{setLoading(false);}
  };

  const crossRecs=result?allPersonas.filter(p=>p.id!==persona.id).slice(0,3):[];
  const handleCrossSelect=(id)=>{
    sessionStorage.setItem("crossTestContent",content);
    onSelectPersona(id);
  };

  return <div style={{height:"100%",overflowY:"auto",background:"#fff"}}>
    <div style={{padding:"24px 32px",borderBottom:"1px solid #f1f5f9",display:"flex",alignItems:"center",gap:12}}>
      <Avatar persona={persona} size={44}/>
      <div>
        <h3 style={{fontSize:18,fontWeight:700,color:"#0f172a",margin:0}}>{persona.name}</h3>
        <div style={{fontSize:12,color:"#64748b"}}>{persona.job} · {persona.age}</div>
      </div>
      <TypeBadge type={persona.type} color={persona.typeColor}/>
    </div>
    <div style={{padding:"24px 32px"}}>
      <div style={{marginBottom:12}}>
        <div style={{fontSize:11,fontWeight:600,color:"#94a3b8",textTransform:"uppercase",letterSpacing:1,marginBottom:8}}>Contenu à tester</div>
        <textarea value={content} onChange={e=>setContent(e.target.value)}
          placeholder={`Collez un synopsis, script, concept, article, transcript...\n\n${persona.name} va analyser depuis son point de vue authentique.`}
          style={{width:"100%",minHeight:120,background:"#f8fafc",border:"1px solid #e2e8f0",borderRadius:10,color:"#374151",padding:"12px",fontSize:13,outline:"none",resize:"vertical",lineHeight:1.6,boxSizing:"border-box",fontFamily:"inherit"}}/>
      </div>
      <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:16,flexWrap:"wrap"}}>
        <label style={{display:"inline-flex",alignItems:"center",gap:6,background:"#f8fafc",border:"1px solid #e2e8f0",color:"#374151",padding:"6px 12px",borderRadius:8,cursor:"pointer",fontSize:12,fontWeight:500}}>
          {fileLoading?"Lecture...":"📎 Fichier (doc, audio, image)"}
          <input type="file" accept=".pdf,.docx,.txt,.md,.mp3,.wav,.m4a,.ogg,.flac,.aac,.webm,.jpg,.jpeg,.png,.gif,.webp" disabled={fileLoading} onChange={e=>e.target.files[0]&&readFile(e.target.files[0])} style={{display:"none"}}/>
        </label>
        {[{label:"📝 Synopsis",v:"Synopsis d'une série verticale africaine de 8 épisodes de 2 minutes sur l'amour à Dakar entre deux jeunes professionnels."},
          {label:"🎬 Script",v:"Script pilote — Scène d'ouverture : une jeune femme reçoit un message de son ex le jour de son mariage. Format vertical, 90 secondes."},
          {label:"🎙️ Podcast",v:"Concept de podcast : 5 minutes d'histoires vraies sur les relations amoureuses en Afrique urbaine, narré par une femme de 30 ans."},
          {label:"📱 TikTok",v:"Série TikTok : 60 secondes par épisode, romance lycée au Maroc, cliffhanger à chaque fin d'épisode, musique trending."},
        ].map(ex=><button key={ex.label} onClick={()=>setContent(ex.v)} style={{background:"#f8fafc",border:"1px solid #e2e8f0",color:"#64748b",padding:"6px 11px",borderRadius:20,cursor:"pointer",fontSize:11,fontWeight:500}}>{ex.label}</button>)}
      </div>
      <button onClick={analyze} disabled={loading||!content.trim()} style={{width:"100%",background:loading||!content.trim()?"#f1f5f9":"#0f172a",border:"none",color:loading||!content.trim()?"#9ca3af":"#fff",padding:"12px",borderRadius:10,cursor:loading||!content.trim()?"not-allowed":"pointer",fontWeight:600,fontSize:14,marginBottom:20}}>
        {loading?`${persona.name} analyse...`:`Analyser avec ${persona.name} →`}
      </button>
      {error&&<div style={{background:"#fef2f2",border:"1px solid #fecaca",borderRadius:10,padding:"12px",color:"#dc2626",fontSize:13,marginBottom:14}}>{error}</div>}
      {result&&<div>
        <div style={{background:"#f8fafc",borderRadius:12,padding:"20px",marginBottom:12,display:"flex",gap:20,alignItems:"center",border:"1px solid #f1f5f9"}}>
          <ScoreRing score={result.score} color={scoreColor} size={84}/>
          <div>
            <div style={{fontSize:18,fontWeight:700,color:"#0f172a",marginBottom:4}}>{result.verdict}</div>
            <div style={{fontSize:12,color:"#94a3b8"}}>Score de résonance avec {persona.name}</div>
          </div>
        </div>
        <div style={{background:"#f8fafc",borderRadius:12,padding:"16px",marginBottom:12,border:"1px solid #f1f5f9"}}>
          <div style={{fontSize:11,fontWeight:600,color:"#94a3b8",textTransform:"uppercase",letterSpacing:1,marginBottom:12}}>Ressenti de {persona.name}</div>
          {result.ressenti&&[
            {key:"accroche",label:"Accroche",icon:"👁",color:"#1a56db"},
            {key:"identification",label:"Identification",icon:"🪞",color:"#16a34a"},
            {key:"friction",label:"Friction",icon:"⚡",color:"#dc2626"},
            {key:"intention",label:"Intention",icon:"↗",color:"#6c2bd9"},
          ].map(({key,label,icon,color})=>result.ressenti[key]&&(
            <div key={key} style={{marginBottom:10,paddingBottom:10,borderBottom:"1px solid #f1f5f9"}}>
              <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:4}}>
                <span style={{fontSize:13}}>{icon}</span>
                <span style={{fontSize:11,fontWeight:700,color,textTransform:"uppercase",letterSpacing:0.8}}>{label}</span>
              </div>
              <div style={{paddingLeft:20,color:"#374151",fontSize:13,lineHeight:1.65,fontStyle:"italic"}}>"{result.ressenti[key]}"</div>
            </div>
          ))}
          {!result.ressenti&&result.reaction&&<div style={{borderLeft:`3px solid ${persona.typeColor}`,paddingLeft:14,color:"#374151",fontSize:13,lineHeight:1.7,fontStyle:"italic"}}>"{result.reaction}"</div>}
        </div>
        <div style={{background:"#f8fafc",borderRadius:12,padding:"16px",marginBottom:12,border:"1px solid #f1f5f9"}}>
          <div style={{fontSize:11,fontWeight:600,color:"#94a3b8",textTransform:"uppercase",letterSpacing:1,marginBottom:12}}>Analyse détaillée</div>
          {Object.entries(result.dimensions).map(([k,v])=><DimBar key={k} label={k} value={v}/>)}
        </div>
        <div style={{background:"#f8fafc",borderRadius:12,padding:"16px",marginBottom:12,border:"1px solid #f1f5f9"}}>
          <div style={{fontSize:11,fontWeight:600,color:"#94a3b8",textTransform:"uppercase",letterSpacing:1,marginBottom:12}}>Pour mieux toucher {persona.name}</div>
          {result.recommandations.map((r,i)=><div key={i} style={{display:"flex",gap:10,marginBottom:8,alignItems:"flex-start"}}>
            <div style={{width:20,height:20,borderRadius:"50%",background:"#0f172a",color:"#fff",display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:700,flexShrink:0}}>{i+1}</div>
            <div style={{fontSize:13,color:"#374151",lineHeight:1.6}}>{r}</div>
          </div>)}
        </div>
        {crossRecs.length>0&&<div style={{background:"#f0f9ff",borderRadius:12,padding:"16px",border:"1px solid #bae6fd"}}>
          <div style={{fontSize:11,fontWeight:600,color:"#0369a1",textTransform:"uppercase",letterSpacing:1,marginBottom:12}}>
            {result.score<50?"Ce contenu pourrait mieux correspondre à...":"Comparez avec d'autres personas"}
          </div>
          {crossRecs.map(p=><button key={p.id} onClick={()=>handleCrossSelect(p.id)} style={{display:"flex",alignItems:"center",gap:10,background:"#fff",border:"1px solid #e0f2fe",borderRadius:8,padding:"8px 12px",cursor:"pointer",width:"100%",marginBottom:6,textAlign:"left"}}>
            <Avatar persona={p} size={30}/>
            <div style={{flex:1}}><div style={{fontSize:13,fontWeight:600,color:"#0f172a"}}>{p.name}</div><div style={{fontSize:11,color:"#64748b"}}>{p.type} · {p.city}</div></div>
            <span style={{fontSize:12,color:"#0369a1"}}>Tester →</span>
          </button>)}
        </div>}
      </div>}
    </div>
  </div>;
}

// ─── UPDATE PANEL ───
function UpdatePanel({persona,onUpdate}) {
  const [loading,setLoading]=useState(false);
  const [proposal,setProposal]=useState(null);
  const [error,setError]=useState(null);
  const fetchUpdate=async()=>{
    setLoading(true);setProposal(null);setError(null);
    const sys=`Tu es un expert en tendances culturelles et médias pour l'Afrique et le Maghreb. Actualise ce persona avec les tendances récentes 2025-2026.
Réponds UNIQUEMENT en JSON valide sans backticks :
{"signaux":["<signal 1>","<signal 2>","<signal 3>","<signal 4>"],"evolutions":[{"champ":"<medias|interests|frustrations|hooks|triggers>","action":"<ajouter|supprimer>","valeur":"<valeur>","raison":"<pourquoi>"}],"synthese":"<résumé 2 phrases>"}`;
    try{
      const text=await callClaude(sys,`Actualise : ${persona.name}, ${persona.age}, ${persona.city}. Type: ${persona.type}. Bio: ${persona.bio}. Médias: ${persona.medias?.join(", ")}. Intérêts: ${persona.interests?.join(", ")}.`);
      setProposal(JSON.parse(text.replace(/\`\`\`json|\`\`\`/g,"").trim()));
    }catch(e){setError("Erreur API.");}
    finally{setLoading(false);}
  };
  const apply=()=>{
    const updated={...persona};
    proposal.evolutions.forEach(ev=>{
      if(!updated[ev.champ]) return;
      if(ev.action==="ajouter"&&!updated[ev.champ].includes(ev.valeur)) updated[ev.champ]=[...updated[ev.champ],ev.valeur];
      if(ev.action==="supprimer") updated[ev.champ]=updated[ev.champ].filter(x=>x!==ev.valeur);
    });
    onUpdate(updated);
  };
  return <div style={{height:"100%",overflowY:"auto",background:"#fff"}}>
    <div style={{padding:"24px 32px",borderBottom:"1px solid #f1f5f9",display:"flex",alignItems:"center",gap:12}}>
      <Avatar persona={persona} size={44}/>
      <div><h3 style={{fontSize:18,fontWeight:700,color:"#0f172a",margin:0}}>{persona.name}</h3><div style={{fontSize:12,color:"#64748b"}}>Actualisation des signaux culturels</div></div>
    </div>
    <div style={{padding:"24px 32px"}}>
      <div style={{background:"#f8fafc",borderRadius:10,padding:"14px",marginBottom:16,border:"1px solid #f1f5f9",fontSize:13,color:"#374151",lineHeight:1.7}}>
        Claude analyse les tendances récentes pour ce profil et propose des mises à jour. Vous validez avant application.
      </div>
      <button onClick={fetchUpdate} disabled={loading} style={{width:"100%",background:loading?"#f1f5f9":"#0f172a",border:"none",color:loading?"#9ca3af":"#fff",padding:"12px",borderRadius:10,cursor:loading?"not-allowed":"pointer",fontWeight:600,fontSize:14,marginBottom:20}}>
        {loading?"Analyse en cours...":"↻ Actualiser avec les tendances récentes"}
      </button>
      {error&&<div style={{background:"#fef2f2",border:"1px solid #fecaca",borderRadius:10,padding:"12px",color:"#dc2626",fontSize:13,marginBottom:14}}>{error}</div>}
      {proposal&&<div>
        <div style={{background:"#f8fafc",borderRadius:10,padding:"14px",marginBottom:10,border:"1px solid #f1f5f9"}}>
          <div style={{fontSize:11,fontWeight:600,color:"#94a3b8",textTransform:"uppercase",letterSpacing:1,marginBottom:10}}>Signaux captés</div>
          {proposal.signaux.map((s,i)=><div key={i} style={{display:"flex",gap:8,marginBottom:6}}><div style={{width:5,height:5,borderRadius:"50%",background:"#0f172a",marginTop:7,flexShrink:0}}/><div style={{fontSize:13,color:"#374151"}}>{s}</div></div>)}
        </div>
        <div style={{background:"#f8fafc",borderRadius:10,padding:"14px",marginBottom:10,border:"1px solid #f1f5f9"}}>
          <div style={{fontSize:11,fontWeight:600,color:"#94a3b8",textTransform:"uppercase",letterSpacing:1,marginBottom:10}}>Évolutions proposées</div>
          {proposal.evolutions.map((ev,i)=><div key={i} style={{background:"#fff",border:"1px solid #f1f5f9",borderRadius:8,padding:"10px 12px",marginBottom:6}}>
            <div style={{display:"flex",gap:6,alignItems:"center",marginBottom:4}}>
              <span style={{background:ev.action==="ajouter"?"#dcfce7":"#fee2e2",color:ev.action==="ajouter"?"#16a34a":"#dc2626",fontSize:10,padding:"1px 7px",borderRadius:20,fontWeight:600}}>{ev.action}</span>
              <span style={{color:"#9ca3af",fontSize:11}}>{ev.champ}</span>
            </div>
            <div style={{fontSize:13,fontWeight:600,color:"#0f172a",marginBottom:2}}>{ev.valeur}</div>
            <div style={{fontSize:12,color:"#64748b"}}>{ev.raison}</div>
          </div>)}
        </div>
        <div style={{background:"#f0fdf4",borderRadius:10,padding:"12px",marginBottom:14,border:"1px solid #bbf7d0",fontSize:13,color:"#374151",lineHeight:1.6}}>{proposal.synthese}</div>
        <div style={{display:"flex",gap:8}}>
          <button onClick={apply} style={{flex:1,background:"#16a34a",border:"none",color:"#fff",padding:"11px",borderRadius:10,cursor:"pointer",fontWeight:600,fontSize:13}}>✓ Appliquer</button>
          <button onClick={()=>setProposal(null)} style={{background:"#f8fafc",border:"1px solid #e2e8f0",color:"#374151",padding:"11px 18px",borderRadius:10,cursor:"pointer"}}>Rejeter</button>
        </div>
      </div>}
    </div>
  </div>;
}

// ─── EDIT FORM ───
function EditForm({initial,onSave,onCancel}) {
  const defaultMd={revenu:"",forfait:"",adoption:"",genres:"",source:""};
  const [form,setForm]=useState({...initial,marketData:{...defaultMd,...(initial?.marketData||{})}});
  const [importing,setImporting]=useState(false);
  const [importStatus,setImportStatus]=useState(null);
  const set=(k,v)=>setForm(f=>({...f,[k]:v}));
  const setMd=(k,v)=>setForm(f=>({...f,marketData:{...f.marketData,[k]:v}}));
  const fs={width:"100%",background:"#f9fafb",border:"1px solid #e5e7eb",borderRadius:8,color:"#111827",padding:"9px 12px",fontSize:13,outline:"none",boxSizing:"border-box"};
  const ls={color:"#6b7280",fontSize:11,textTransform:"uppercase",letterSpacing:1,marginBottom:5,display:"block",fontWeight:600};

  const importFromDoc=async(file)=>{
    setImporting(true);setImportStatus("Lecture...");
    try{
      const base64=await new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res(r.result.split(",")[1]);r.onerror=rej;r.readAsDataURL(file);});
      const isPDF=file.type==="application/pdf";
      setImportStatus("Analyse par l'IA...");
      const apiKey=import.meta.env.VITE_ANTHROPIC_API_KEY;
      const sys=`Extrais les informations du document pour enrichir un persona éditorial.
Réponds UNIQUEMENT en JSON valide sans backticks :
{"name":null,"age":null,"city":null,"job":null,"bio":null,"medias":[],"interests":[],"frustrations":[],"hooks":[],"triggers":[],"tags":[],"marketData":{"revenu":null,"forfait":null,"adoption":null,"genres":null,"source":null},"notes":null}`;
      // Determine content type and build userContent
      const isDocxFile=file.name.endsWith(".docx")||file.type==="application/vnd.openxmlformats-officedocument.wordprocessingml.document";
      let userContent;
      if(isPDF){
        userContent=[{type:"document",source:{type:"base64",media_type:"application/pdf",data:base64}},{type:"text",text:`Extrais les infos pour "${form.name||"nouveau"}"`}];
      } else if(isDocxFile){
        const arrBuf=await new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res(r.result);r.onerror=rej;r.readAsArrayBuffer(file);});
        const mammothResult=await mammoth.extractRawText({arrayBuffer:arrBuf});
        const docText=mammothResult.value?.trim().substring(0,6000)||"[texte non extrait]";
        userContent=[{type:"text",text:`Extrais les infos de ce document Word pour "${form.name||"nouveau"}":\n\n${docText}`}]

      } else {
        const textDec=new TextDecoder("utf-8",{fatal:false});
        const textContent=textDec.decode(Uint8Array.from(atob(base64),c=>c.charCodeAt(0))).substring(0,6000);
        userContent=[{type:"text",text:`Extrais les infos de ce document pour "${form.name||"nouveau"}":

${textContent}`}];
      }
      const res=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json","x-api-key":apiKey,"anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:2000,system:sys,messages:[{role:"user",content:userContent}]})});
      const data=await res.json();
      const extracted=JSON.parse(data.content.map(i=>i.text||"").join("").replace(/\`\`\`json|\`\`\`/g,"").trim());
      setForm(f=>{
        const m={...f};
        if(extracted.name&&!f.name) m.name=extracted.name;
        if(extracted.age&&!f.age) m.age=extracted.age;
        if(extracted.city&&!f.city) m.city=extracted.city;
        if(extracted.job&&!f.job) m.job=extracted.job;
        if(extracted.bio) m.bio=f.bio?`${f.bio}\n\n[Import] ${extracted.bio}`:extracted.bio;
        ["medias","interests","frustrations","hooks","triggers","tags"].forEach(k=>{
          if(extracted[k]?.length){const ex=f[k]||[];const ni=extracted[k].filter(i=>!ex.some(e=>e.toLowerCase()===i.toLowerCase()));m[k]=[...ex,...ni];}
        });
        if(extracted.marketData){m.marketData={...f.marketData};Object.entries(extracted.marketData).forEach(([k,v])=>{if(v&&!m.marketData[k])m.marketData[k]=v;});}
        if(extracted.notes) m.notes=f.notes?`${f.notes}\n\n[Import] ${extracted.notes}`:extracted.notes;
        return m;
      });
      setImportStatus("✓ Document importé");setTimeout(()=>setImportStatus(null),3000);
    }catch(e){setImportStatus("Erreur import.");setTimeout(()=>setImportStatus(null),3000);}
    finally{setImporting(false);}
  };

  return <div style={{height:"100%",overflowY:"auto",background:"#fff",padding:"24px 32px"}}>
    <h3 style={{fontSize:20,fontWeight:700,color:"#0f172a",marginBottom:20}}>{initial?.id?"Modifier — "+initial.name:"Nouveau persona"}</h3>
    <div style={{background:"#f0f9ff",border:"1px solid #bae6fd",borderRadius:10,padding:"12px 16px",marginBottom:18}}>
      <div style={{fontSize:11,fontWeight:600,color:"#0369a1",textTransform:"uppercase",letterSpacing:1,marginBottom:6}}>✨ Enrichir depuis un document</div>
      <p style={{color:"#64748b",fontSize:12,margin:"0 0 10px",lineHeight:1.5}}>Importez une fiche persona, étude terrain ou tout document descriptif. L'IA en extrait les informations automatiquement.</p>
      <label style={{display:"inline-flex",alignItems:"center",gap:6,background:"#fff",border:"1px solid #bae6fd",color:"#0369a1",padding:"7px 14px",borderRadius:8,cursor:importing?"not-allowed":"pointer",fontSize:12,fontWeight:600}}>
        {importing?"Analyse...":"📎 Sélectionner un document"}
        <input type="file" accept=".pdf,.docx,.txt,.md" disabled={importing} onChange={e=>e.target.files[0]&&importFromDoc(e.target.files[0])} style={{display:"none"}}/>
      </label>
      {importStatus&&<span style={{marginLeft:10,fontSize:12,color:importStatus.startsWith("✓")?"#16a34a":"#d97706"}}>{importStatus}</span>}
    </div>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:12}}>
      <div><label style={ls}>Prénom</label><input value={form.name||""} onChange={e=>set("name",e.target.value)} style={fs}/></div>
      <div><label style={ls}>Emoji</label><input value={form.emoji||""} onChange={e=>set("emoji",e.target.value)} style={{...fs,textAlign:"center",fontSize:22}}/></div>
      <div><label style={ls}>Âge</label><input value={form.age||""} onChange={e=>set("age",e.target.value)} style={fs}/></div>
      <div><label style={ls}>Ville</label><input value={form.city||""} onChange={e=>set("city",e.target.value)} style={fs}/></div>
      <div style={{gridColumn:"1/-1"}}><label style={ls}>Profession</label><input value={form.job||""} onChange={e=>set("job",e.target.value)} style={fs}/></div>
      <div>
        <label style={ls}>Type</label>
        <select value={form.type||""} onChange={e=>{const opt=TYPE_OPTIONS.find(o=>o.label===e.target.value);set("type",e.target.value);if(opt)set("typeColor",opt.color);}} style={{...fs,appearance:"none"}}>
          {TYPE_OPTIONS.map(o=><option key={o.label} value={o.label}>{o.label}</option>)}
        </select>
      </div>
      <div><label style={ls}>Projet</label><input value={form.project||""} onChange={e=>set("project",e.target.value)} style={fs}/></div>
    </div>
    <div style={{marginBottom:12}}><label style={ls}>Bio</label><textarea value={form.bio||""} onChange={e=>set("bio",e.target.value)} style={{...fs,minHeight:80,resize:"vertical"}}/></div>
    {[["medias","Médias"],["interests","Intérêts"],["frustrations","Frustrations"],["hooks","Accroches"],["triggers","Déclencheurs"],["tags","Tags"]].map(([k,l])=>(
      <div key={k} style={{marginBottom:10}}><label style={ls}>{l}</label><TagInput value={form[k]||[]} onChange={v=>set(k,v)} placeholder={`Ajouter ${l.toLowerCase()}...`}/></div>
    ))}
    <div style={{background:"#f0f9ff",borderRadius:10,padding:"12px 14px",marginBottom:12,border:"1px solid #bae6fd"}}>
      <div style={{fontSize:11,fontWeight:600,color:"#0369a1",textTransform:"uppercase",letterSpacing:1,marginBottom:10}}>Données marché</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
        <div><label style={ls}>Revenu</label><input value={form.marketData.revenu||""} onChange={e=>setMd("revenu",e.target.value)} style={fs}/></div>
        <div><label style={ls}>Forfait</label><input value={form.marketData.forfait||""} onChange={e=>setMd("forfait",e.target.value)} style={fs}/></div>
        <div><label style={ls}>Adoption</label><input value={form.marketData.adoption||""} onChange={e=>setMd("adoption",e.target.value)} style={fs}/></div>
        <div><label style={ls}>Genres %</label><input value={form.marketData.genres||""} onChange={e=>setMd("genres",e.target.value)} style={fs}/></div>
        <div style={{gridColumn:"1/-1"}}><label style={ls}>Source</label><input value={form.marketData.source||""} onChange={e=>setMd("source",e.target.value)} style={fs}/></div>
      </div>
    </div>
    <div style={{marginBottom:18}}><label style={ls}>Notes</label><textarea value={form.notes||""} onChange={e=>set("notes",e.target.value)} style={{...fs,minHeight:70,resize:"vertical"}}/></div>
    <div style={{display:"flex",gap:10}}>
      <button onClick={()=>onSave({...form,id:form.id||Date.now().toString()})} style={{background:"#0f172a",border:"none",color:"#fff",padding:"10px 22px",borderRadius:8,cursor:"pointer",fontWeight:600,fontSize:14}}>Enregistrer</button>
      <button onClick={onCancel} style={{background:"#f8fafc",border:"1px solid #e2e8f0",color:"#374151",padding:"10px 22px",borderRadius:8,cursor:"pointer"}}>Annuler</button>
    </div>
  </div>;
}

// ─── SPACE WORKSPACE ───
function SpaceWorkspace({space,personas,onUpdateSpace,onBack,onUpdatePersona,onDeletePersona}) {
  const [selected,setSelected]=useState(null);
  const [mode,setMode]=useState("detail");
  const [search,setSearch]=useState("");
  const spacePersonas=personas.filter(p=>space.personaIds?.includes(p.id));
  const filtered=spacePersonas.filter(p=>{
    const q=search.toLowerCase();
    return !q||p.name.toLowerCase().includes(q)||p.type.toLowerCase().includes(q)||p.city?.toLowerCase().includes(q);
  });
  const selectedPersona=personas.find(p=>p.id===selected);

  const addPersona=(persona)=>{
    const updated={...space,personaIds:[...(space.personaIds||[]),persona.id]};
    onUpdateSpace(updated,persona);
    setSelected(persona.id);
    setMode("detail");
  };

  const removePersona=(id)=>{
    if(!confirm("Retirer ce persona de l'espace ?")) return;
    onUpdateSpace({...space,personaIds:space.personaIds.filter(pid=>pid!==id)},null);
    setSelected(null);
  };

  return <div style={{display:"flex",flexDirection:"column",height:"100vh",background:"#fff"}}>
    {/* Space header */}
    <div style={{borderBottom:"1px solid #f1f5f9",padding:"12px 20px",display:"flex",alignItems:"center",gap:12,background:"#fff",flexShrink:0}}>
      <button onClick={onBack} style={{background:"transparent",border:"none",color:"#64748b",cursor:"pointer",fontSize:13,display:"flex",alignItems:"center",gap:4,padding:"4px 8px",borderRadius:6}}
        onMouseEnter={e=>e.currentTarget.style.background="#f8fafc"} onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
        ← Espaces
      </button>
      <div style={{width:1,height:16,background:"#e2e8f0"}}/>
      <div style={{width:28,height:28,borderRadius:8,background:space.color+"15",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16}}>{space.icon}</div>
      <span style={{fontWeight:700,fontSize:14,color:"#0f172a"}}>{space.name}</span>
      <span style={{fontSize:12,color:"#94a3b8"}}>{spacePersonas.length} persona{spacePersonas.length>1?"s":""}</span>
      <div style={{flex:1}}/>
      <button onClick={()=>{setSelected(null);setMode("new");}} style={{background:"#0f172a",border:"none",color:"#fff",padding:"6px 14px",borderRadius:8,cursor:"pointer",fontSize:12,fontWeight:600}}>+ Nouveau persona</button>
    </div>

    <div style={{display:"flex",flex:1,overflow:"hidden"}}>
      {/* Sidebar */}
      <div style={{width:250,borderRight:"1px solid #f1f5f9",display:"flex",flexDirection:"column",background:"#fafafa"}}>
        <div style={{padding:"10px 12px",borderBottom:"1px solid #f1f5f9"}}>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Rechercher…"
            style={{width:"100%",background:"#fff",border:"1px solid #e5e7eb",borderRadius:8,color:"#374151",padding:"7px 11px",fontSize:12,outline:"none",boxSizing:"border-box"}}/>
        </div>
        <div style={{overflowY:"auto",flex:1,padding:"8px"}}>
          {filtered.length===0&&<div style={{color:"#cbd5e1",fontSize:13,textAlign:"center",padding:24}}>Aucun persona</div>}
          {filtered.map(p=><PersonaCard key={p.id} persona={p} selected={selected===p.id} onClick={()=>{setSelected(p.id);setMode("detail");}}/>)}
        </div>
        <div style={{padding:"8px 12px",borderTop:"1px solid #f1f5f9",color:"#cbd5e1",fontSize:10,background:"#fafafa"}}>{spacePersonas.length} personas</div>
      </div>

      {/* Main */}
      <div style={{flex:1,overflow:"hidden"}}>
        {mode==="new"&&<EditForm
          initial={{id:"",name:"",emoji:"👤",age:"",city:"",job:"",type:"Curieux",typeColor:"#b45309",chapter:space.name,bio:"",medias:[],interests:[],frustrations:[],hooks:[],triggers:[],marketData:{revenu:"",forfait:"",adoption:"",genres:"",source:""},notes:"",project:space.name,tags:[]}}
          onSave={addPersona} onCancel={()=>setMode(selected?"detail":"welcome")}/>}
        {mode==="edit"&&selectedPersona&&<EditForm initial={selectedPersona} onSave={p=>{onUpdatePersona(p);setMode("detail");}} onCancel={()=>setMode("detail")}/>}
        {mode==="test"&&selectedPersona&&<TestPanel persona={selectedPersona} allPersonas={spacePersonas} onSelectPersona={id=>{setSelected(id);setMode("test");}}/>}
        {mode==="update"&&selectedPersona&&<UpdatePanel persona={selectedPersona} onUpdate={p=>{onUpdatePersona(p);setMode("detail");}}/>}
        {mode==="detail"&&selectedPersona&&<DetailView persona={selectedPersona} onEdit={()=>setMode("edit")} onDelete={()=>{removePersona(selectedPersona.id);onDeletePersona(selectedPersona.id);}} onTest={()=>setMode("test")} onUpdate={()=>setMode("update")}/>}
        {(mode==="detail"||mode==="welcome")&&!selectedPersona&&<div style={{height:"100%",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:16,background:"#fff"}}>
          <div style={{width:56,height:56,borderRadius:16,background:space.color+"15",display:"flex",alignItems:"center",justifyContent:"center",fontSize:28}}>{space.icon}</div>
          <div style={{textAlign:"center"}}>
            <div style={{fontWeight:700,fontSize:18,color:"#0f172a",marginBottom:4}}>{space.name}</div>
            <div style={{fontSize:13,color:"#94a3b8"}}>{spacePersonas.length>0?"Sélectionnez un persona":"Créez votre premier persona"}</div>
          </div>
          <button onClick={()=>setMode("new")} style={{background:"#0f172a",border:"none",color:"#fff",padding:"10px 22px",borderRadius:10,cursor:"pointer",fontSize:13,fontWeight:600}}>+ Nouveau persona</button>
        </div>}
      </div>
    </div>
  </div>;
}

// ─── MAIN APP ───
export default function App() {
  const [personas,setPersonas]=useState([]);
  const [spaces,setSpaces]=useState([]);
  const [currentSpaceId,setCurrentSpaceId]=useState(null);
  const [showCreateSpace,setShowCreateSpace]=useState(false);
  const [loaded,setLoaded]=useState(false);

  useEffect(()=>{
    const saved=loadData();
    if(saved?.personas?.length&&saved?.spaces?.length){
      setPersonas(saved.personas);
      setSpaces(saved.spaces);
    } else {
      setPersonas(DEFAULT_PERSONAS);
      setSpaces(DEFAULT_SPACES);
    }
    setLoaded(true);
  },[]);

  const save=(p,s)=>{setPersonas(p);setSpaces(s);saveData({personas:p,spaces:s});};

  const handleCreateSpace=(space)=>{
    const newSpaces=[...spaces,space];
    save(personas,newSpaces);
    setShowCreateSpace(false);
    setCurrentSpaceId(space.id);
  };

  const handleDeleteSpace=(id)=>{
    if(!confirm("Supprimer cet espace ?")) return;
    save(personas,spaces.filter(s=>s.id!==id));
  };

  const handleUpdateSpace=(updatedSpace,newPersona)=>{
    const newSpaces=spaces.map(s=>s.id===updatedSpace.id?updatedSpace:s);
    const newPersonas=newPersona?[...personas.filter(p=>p.id!==newPersona.id),newPersona]:personas;
    save(newPersonas,newSpaces);
    setPersonas(newPersonas);
    setSpaces(newSpaces);
  };

  const handleUpdatePersona=(persona)=>{
    const newPersonas=personas.map(p=>p.id===persona.id?persona:p);
    save(newPersonas,spaces);
  };

  const handleDeletePersona=(id)=>{
    const newPersonas=personas.filter(p=>p.id!==id);
    const newSpaces=spaces.map(s=>({...s,personaIds:(s.personaIds||[]).filter(pid=>pid!==id)}));
    save(newPersonas,newSpaces);
  };

  const currentSpace=spaces.find(s=>s.id===currentSpaceId);

  if(!loaded) return <div style={{background:"#fff",minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",color:"#94a3b8"}}>Chargement…</div>;

  return <div style={{fontFamily:"'-apple-system','SF Pro Text','Helvetica Neue',system-ui,sans-serif"}}>
    {/* Sticky header on spaces home */}
    {!currentSpaceId&&<div style={{position:"sticky",top:0,zIndex:100,borderBottom:"1px solid #f1f5f9",padding:"12px 20px",display:"flex",alignItems:"center",gap:12,background:"rgba(255,255,255,0.95)",backdropFilter:"blur(10px)"}}>
      <div style={{display:"flex",alignItems:"center",gap:8}}>
        <div style={{width:28,height:28,background:"#0f172a",borderRadius:7,display:"flex",alignItems:"center",justifyContent:"center"}}>
          <span style={{color:"#fff",fontSize:14,fontWeight:800}}>P</span>
        </div>
        <span style={{fontSize:15,fontWeight:700,color:"#0f172a",letterSpacing:-0.3}}>PersonaLab</span>
      </div>
      <div style={{flex:1}}/>
      <button onClick={()=>setShowCreateSpace(true)} style={{background:"#0f172a",border:"none",color:"#fff",padding:"7px 16px",borderRadius:8,cursor:"pointer",fontSize:12,fontWeight:600}}>+ Nouvel espace</button>
    </div>}

    {currentSpace
      ? <SpaceWorkspace
          space={currentSpace}
          personas={personas}
          onUpdateSpace={handleUpdateSpace}
          onBack={()=>setCurrentSpaceId(null)}
          onUpdatePersona={handleUpdatePersona}
          onDeletePersona={handleDeletePersona}/>
      : <SpacesHome
          spaces={spaces}
          personas={personas}
          onOpenSpace={setCurrentSpaceId}
          onCreateSpace={()=>setShowCreateSpace(true)}
          onDeleteSpace={handleDeleteSpace}/>
    }

    {showCreateSpace&&<CreateSpaceModal onSave={handleCreateSpace} onCancel={()=>setShowCreateSpace(false)}/>}
  </div>;
}
